@app.middleware("http")
async def security_headers_middleware(request: Request, call_next):
    response = await call_next(request)
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("X-Frame-Options", "DENY")
    response.headers.setdefault("Referrer-Policy", "no-referrer")
    response.headers.setdefault("Permissions-Policy", "camera=(), microphone=(), geolocation=()")
    response.headers.setdefault("Content-Security-Policy", "frame-ancestors 'none'; base-uri 'self'; form-action 'self'")
    if SECURE_COOKIES:
        response.headers.setdefault("Strict-Transport-Security", "max-age=31536000; includeSubDomains")
    return response


def _utc_now():
    return datetime.datetime.utcnow().replace(microsecond=0).isoformat() + "Z"


def _client_ip(request: Request):
    forwarded = request.headers.get("x-forwarded-for", "")
    if forwarded:
        return forwarded.split(",")[0].strip()
    return request.client.host if request.client else "unknown"


def _safe_load_security():
    return load_json(SECURITY_FILE, {"login_failures": {}})


def _save_security(data):
    save_json(SECURITY_FILE, data)


def _audit_event(request: Request | None, actor: str, action: str, entity_type: str = "system", entity_id: str = "", details=None):
    try:
        event = {
            "ts": _utc_now(),
            "actor": actor or "anonymous",
            "action": action,
            "entity_type": entity_type,
            "entity_id": entity_id or "",
            "ip": _client_ip(request) if request else "system",
            "details": details or {},
        }
        with open(AUDIT_LOG_FILE, "a", encoding="utf-8") as f:
            f.write(json.dumps(event, ensure_ascii=False) + "\n")
    except Exception:
        pass


def _is_locked(username: str):
    sec = _safe_load_security()
    rec = sec.get("login_failures", {}).get(username.lower())
    if not rec:
        return False, 0
    locked_until = float(rec.get("locked_until", 0) or 0)
    remaining = int(max(0, locked_until - time.time()))
    return remaining > 0, remaining


def _record_failed_login(request: Request, username: str):
    username = username.strip().lower()
    sec = _safe_load_security()
    failures = sec.setdefault("login_failures", {})
    rec = failures.setdefault(username, {"count": 0, "first_failed_at": _utc_now()})
    rec["count"] = int(rec.get("count", 0)) + 1
    rec["last_failed_at"] = _utc_now()
    locked_now = False
    if rec["count"] >= MAX_FAILED_LOGINS:
        if not rec.get("locked_until") or float(rec.get("locked_until", 0) or 0) < time.time():
            locked_now = True
        rec["locked_until"] = time.time() + LOCKOUT_SECONDS
        rec["lockout_at"] = _utc_now()
    _save_security(sec)
    _audit_event(request, username or "unknown", "login_failed", "user", username, {"count": rec.get("count", 0), "locked": bool(rec.get("locked_until"))})
    if locked_now:
        _audit_event(request, username or "unknown", "account_locked", "user", username, {"failed_attempts": rec.get("count", 0), "lockout_seconds": LOCKOUT_SECONDS})


def _clear_failed_login(username: str):
    sec = _safe_load_security()
    sec.get("login_failures", {}).pop(username.strip().lower(), None)
    _save_security(sec)


def _lock_record(username: str):
    sec = _safe_load_security()
    return sec.get("login_failures", {}).get(str(username or "").strip().lower(), {}) or {}

def _lock_status(username: str):
    username = str(username or "").strip().lower()
    rec = _lock_record(username)
    locked_until = float(rec.get("locked_until", 0) or 0)
    remaining = int(max(0, locked_until - time.time()))
    return {
        "count": int(rec.get("count", 0) or 0),
        "locked": remaining > 0,
        "remaining_seconds": remaining,
        "locked_until": locked_until,
        "last_failed_at": rec.get("last_failed_at", ""),
        "lockout_at": rec.get("lockout_at", ""),
    }

def lock_status_map(users):
    return {u.get("username", ""): _lock_status(u.get("username", "")) for u in users}

def _unlock_user(username: str):
    _clear_failed_login(username)

def count_locked_users():
    return sum(1 for u in load_users() if _lock_status(u.get("username", "")).get("locked"))


def validate_password_strength(password: str):
    if len(password or "") < PASSWORD_MIN_LENGTH:
        return f"Password must be at least {PASSWORD_MIN_LENGTH} characters"
    if not any(c.isupper() for c in password):
        return "Password must include at least one uppercase letter"
    if not any(c.islower() for c in password):
        return "Password must include at least one lowercase letter"
    if not any(c.isdigit() for c in password):
        return "Password must include at least one number"
    if not any(not c.isalnum() for c in password):
        return "Password must include at least one special character"
    return ""


# -----------------------------
# MFA / TOTP helpers (app-level; no corporate Entra dependency)
# -----------------------------

def _base32_pad(secret: str) -> str:
    secret = str(secret or "").replace(" ", "").upper()
    return secret + ("=" * ((8 - len(secret) % 8) % 8))

def generate_totp_secret() -> str:
    return base64.b32encode(secrets.token_bytes(20)).decode("ascii").rstrip("=")

def _hotp(secret: str, counter: int, digits: int = 6) -> str:
    key = base64.b32decode(_base32_pad(secret), casefold=True)
    msg = int(counter).to_bytes(8, "big")
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    offset = digest[-1] & 0x0F
    code = ((digest[offset] & 0x7F) << 24) | ((digest[offset + 1] & 0xFF) << 16) | ((digest[offset + 2] & 0xFF) << 8) | (digest[offset + 3] & 0xFF)
    return str(code % (10 ** digits)).zfill(digits)

def totp_code(secret: str, for_time: int | None = None) -> str:
    for_time = int(for_time or time.time())
    return _hotp(secret, for_time // MFA_PERIOD_SECONDS)

def verify_totp(secret: str, code: str) -> bool:
    code = str(code or "").strip().replace(" ", "")
    if not (code.isdigit() and len(code) == 6 and secret):
        return False
    now_counter = int(time.time()) // MFA_PERIOD_SECONDS
    for offset in range(-MFA_ALLOWED_WINDOW, MFA_ALLOWED_WINDOW + 1):
        if hmac.compare_digest(_hotp(secret, now_counter + offset), code):
            return True
    return False

def mfa_otpauth_uri(user) -> str:
    username = user.get("username", "user")
    label = f"{MFA_ISSUER}:{username}"
    params = {"secret": user.get("mfa_secret", ""), "issuer": MFA_ISSUER, "algorithm": "SHA1", "digits": "6", "period": str(MFA_PERIOD_SECONDS)}
    return "otpauth://totp/" + urllib.parse.quote(label) + "?" + urllib.parse.urlencode(params)

def qrcode_data_uri(payload: str) -> str:
    import qrcode
    img = qrcode.make(payload)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return "data:image/png;base64," + base64.b64encode(buf.getvalue()).decode("ascii")

def pending_mfa_user(request: Request):
    username = request.session.get("pending_mfa_username")
    if not username:
        return None
    return next((u for u in load_users() if u.get("username") == username and u.get("active", True)), None)

def complete_login_after_mfa(request: Request, user):
    request.session.clear()
    request.session["username"] = user["username"]
    request.session["login_at"] = int(time.time())
    request.session["mfa_passed"] = True

