def normalise_domains(value):
    if value is None:
        return []
    if isinstance(value, list):
        raw = value
    else:
        raw = str(value).replace(";", ",").split(",")
    cleaned = []
    for d in raw:
        d = canonical_domain(str(d).strip())
        if d and d not in cleaned:
            cleaned.append(d)
    return cleaned

DOMAIN_ALIASES = {
    "fm": "Fault Management",
    "fault management": "Fault Management",
    "pm": "Performance Management",
    "performance management": "Performance Management",
    "cm": "Configuration Management",
    "configuration management": "Configuration Management",
    "oss": "OSS",
}

def role_of(user):
    return str((user or {}).get("role", "")).strip().lower()

def canonical_domain(value):
    value = str(value or "").strip()
    if not value:
        return ""
    return DOMAIN_ALIASES.get(value.lower(), value)

def domains_match(a, b):
    return canonical_domain(a).lower() == canonical_domain(b).lower()

def available_domains():
    domains = list(DEFAULT_DOMAINS)
    try:
        for c in load_use_cases():
            d = canonical_domain(str(c.get("domain", "")).strip())
            if d and d not in domains:
                domains.append(d)
    except Exception:
        pass
    return domains

def user_allowed_domains(user):
    if role_of(user) == "super_admin":
        return available_domains()
    return normalise_domains(user.get("domains", []))

