def _json_key_for_path(path: Path):
    return JSON_TO_DB_KEY.get(Path(path).name)

def _read_json_file(path: Path, default):
    path = Path(path)
    if not path.exists():
        return default
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)

def _db_connect():
    conn = sqlite3.connect(DB_FILE, timeout=30)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA synchronous=NORMAL")
    conn.execute("PRAGMA foreign_keys=ON")
    return conn

def _backup_db_before_write():
    try:
        if not DB_FILE.exists():
            return
        stamp = datetime.datetime.utcnow().strftime("%Y%m%dT%H%M%SZ")
        DB_BACKUP_DIR.mkdir(parents=True, exist_ok=True)
        shutil.copy2(DB_FILE, DB_BACKUP_DIR / f"aidash_v4_{stamp}.db")
    except Exception:
        pass

def _db_get(key: str, default):
    if STORAGE_BACKEND != "sqlite":
        return default
    try:
        init_sqlite_storage()
        with _db_connect() as conn:
            row = conn.execute("SELECT value FROM kv_store WHERE key = ?", (key,)).fetchone()
        if not row:
            return default
        return json.loads(row["value"])
    except Exception:
        return default

def _db_set(key: str, value):
    if STORAGE_BACKEND != "sqlite":
        return False
    init_sqlite_storage()
    _backup_db_before_write()
    payload = json.dumps(value, ensure_ascii=False, indent=2)
    with _db_connect() as conn:
        conn.execute(
            """
            INSERT INTO kv_store(key, value, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = excluded.updated_at
            """,
            (key, payload, _utc_now()),
        )
    return True

SQLITE_INIT_DONE = False

def _db_metadata_get(conn, key: str, default: str = ""):
    row = conn.execute("SELECT value FROM app_metadata WHERE key = ?", (key,)).fetchone()
    return row["value"] if row else default

def _db_metadata_set(conn, key: str, value: str):
    conn.execute("INSERT INTO app_metadata(key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value", (key, value))

def _migrate_sqlite_v5(conn):
    """One-time V5 migration: backup DB, add MFA fields to user records, bump schema version."""
    schema_version = _db_metadata_get(conn, "schema_version", "4")
    if schema_version == "5":
        return
    try:
        if DB_FILE.exists() and _db_metadata_get(conn, "v5_pre_mfa_backup", "") != "done":
            stamp = datetime.datetime.utcnow().strftime("%Y%m%dT%H%M%SZ")
            DB_BACKUP_DIR.mkdir(parents=True, exist_ok=True)
            shutil.copy2(DB_FILE, DB_BACKUP_DIR / f"aidash_v4_pre_mfa_{stamp}.db")
            _db_metadata_set(conn, "v5_pre_mfa_backup", "done")
    except Exception:
        pass
    row = conn.execute("SELECT value FROM kv_store WHERE key = ?", ("users",)).fetchone()
    users = []
    if row:
        try:
            users = json.loads(row["value"])
        except Exception:
            users = []
    changed = False
    for u in users:
        if "mfa_enabled" not in u:
            u["mfa_enabled"] = False; changed = True
        if "mfa_secret" not in u:
            u["mfa_secret"] = ""; changed = True
        if "mfa_confirmed_at" not in u:
            u["mfa_confirmed_at"] = ""; changed = True
    if changed:
        conn.execute("UPDATE kv_store SET value = ?, updated_at = ? WHERE key = ?", (json.dumps(users, ensure_ascii=False, indent=2), _utc_now(), "users"))
        try:
            _write_json_shadow_file(USERS_FILE, users)
        except Exception:
            pass
    _db_metadata_set(conn, "schema_version", "5")

def init_sqlite_storage():
    global SQLITE_INIT_DONE
    if STORAGE_BACKEND != "sqlite":
        return
    if SQLITE_INIT_DONE:
        return
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    with _db_connect() as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS kv_store (
                key TEXT PRIMARY KEY,
                value TEXT NOT NULL,
                updated_at TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS app_metadata (
                key TEXT PRIMARY KEY,
                value TEXT NOT NULL
            )
            """
        )
        conn.execute("INSERT OR IGNORE INTO app_metadata(key, value) VALUES ('schema_version', '4')")
        existing = {r["key"] for r in conn.execute("SELECT key FROM kv_store").fetchall()}
        seed_map = {
            "use_cases": DATA_FILE,
            "users": USERS_FILE,
            "settings": SETTINGS_FILE,
            "security": SECURITY_FILE,
        }
        for key, path in seed_map.items():
            if key in existing:
                continue
            value = _read_json_file(path, DB_DEFAULTS[key])
            conn.execute(
                "INSERT OR IGNORE INTO kv_store(key, value, updated_at) VALUES (?, ?, ?)",
                (key, json.dumps(value, ensure_ascii=False, indent=2), _utc_now()),
            )
        _migrate_sqlite_v5(conn)
    SQLITE_INIT_DONE = True

def get_schema_version():
    if STORAGE_BACKEND != "sqlite":
        return "json"
    try:
        init_sqlite_storage()
        with _db_connect() as conn:
            return _db_metadata_get(conn, "schema_version", "4")
    except Exception:
        return "unknown"

