def _backup_before_write(path: Path):
    try:
        path = Path(path)
        if not path.exists() or path.name == "security.json":
            return
        stamp = datetime.datetime.utcnow().strftime("%Y%m%dT%H%M%SZ")
        target_dir = BACKUP_DIR / path.stem
        target_dir.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, target_dir / f"{path.stem}_{stamp}{path.suffix}")
    except Exception:
        pass

def _write_json_shadow_file(path: Path, data):
    """Maintain a readable JSON shadow file for emergency/manual export only."""
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_suffix(path.suffix + ".tmp")
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)
    os.replace(tmp, path)

def load_json(path, default):
    path = Path(path)
    key = _json_key_for_path(path)
    if key and STORAGE_BACKEND == "sqlite":
        return _db_get(key, default)
    return _read_json_file(path, default)

def save_json(path, data):
    path = Path(path)
    key = _json_key_for_path(path)
    if key and STORAGE_BACKEND == "sqlite":
        _db_set(key, data)
        # Keep JSON shadow files in sync on the persistent disk for backup/diagnostics.
        try:
            _write_json_shadow_file(path, data)
        except Exception:
            pass
        return
    path.parent.mkdir(parents=True, exist_ok=True)
    _backup_before_write(path)
    _write_json_shadow_file(path, data)

