def _clean_numeric_text(v):
    """Normalise values coming from dashboard CSV / Excel-generated CSV files."""
    if v in [None, ""]:
        return ""
    text = str(v).strip()
    if not text:
        return ""
    # Common CSV exports may include currency symbols, spaces, commas or percentage signs.
    text = text.replace("\ufeff", "").replace("R", "").replace("r", "")
    text = text.replace("ZAR", "").replace("zar", "")
    text = text.replace(",", "").replace("%", "").strip()
    # Accounting negatives: (1234) -> -1234
    if text.startswith("(") and text.endswith(")"):
        text = "-" + text[1:-1]
    return text

def _eval_import_formula(expr, context=None, default=0):
    """Safely evaluate simple numeric Excel formulas used in imported CSV files.

    This intentionally supports only arithmetic formulas and same-row references such as:
    =20*22*8*12*0.12
    =700*asoc_ai_use_cases__4[[#This Row],[hours_saved]]
    """
    context = context or {}
    text = str(expr or "").strip()
    if not text.startswith("="):
        return default
    formula = text[1:]
    import re

    def repl_same_row(match):
        field = match.group(1).strip()
        return str(as_number(context.get(field, 0), 0))

    # Replace Excel table same-row references, with or without the table prefix.
    formula = re.sub(r"[A-Za-z0-9_]*\[\[#This Row\],\[([^\]]+)\]\]", repl_same_row, formula)
    formula = re.sub(r"\[\[#This Row\],\[([^\]]+)\]\]", repl_same_row, formula)

    # Allow only numeric arithmetic after replacement.
    if not re.fullmatch(r"[0-9\.\+\-\*\/\(\)\s]+", formula):
        return default
    try:
        return eval(formula, {"__builtins__": {}}, {})
    except Exception:
        return default

def as_number(v, default=0):
    try:
        if v in [None, ""]:
            return default
        if isinstance(v, (int, float)):
            return v
        text = str(v).strip()
        if text.startswith("="):
            return _eval_import_formula(text, {}, default)
        text = _clean_numeric_text(text)
        if text in ["", "+", "-"]:
            return default
        value = float(text)
        return int(value) if value.is_integer() else value
    except Exception:
        return default

def normalise_metric_value(field, value):
    """Normalise numeric form/import values to avoid browser step-validation issues.

    Whole-number benefit fields are stored as integers. Percentage/score fields
    are rounded to a clean decimal so values like 12.000000000000002 do not
    render back into HTML inputs and trigger validation errors.
    """
    n = as_number(value)
    if field in ["annual_value", "implementation_cost", "hours_saved"]:
        try:
            return int(round(float(n)))
        except Exception:
            return 0
    if field in ["mttr_improvement", "reuse_score"]:
        try:
            n = round(float(n), 2)
            return int(n) if float(n).is_integer() else n
        except Exception:
            return 0
    return n

def safe_div(a, b):
    a = as_number(a); b = as_number(b)
    return 0 if b == 0 else a / b

def summary(use_cases, settings=None):
    settings = settings or load_settings()
    total_value = sum(as_number(x.get("annual_value", 0)) for x in use_cases)
    implementation_cost = sum(as_number(x.get("implementation_cost", 0)) for x in use_cases)
    total_hours = sum(as_number(x.get("hours_saved", 0)) for x in use_cases)
    production = sum(1 for x in use_cases if x.get("status") == "Production")
    sandbox = sum(1 for x in use_cases if x.get("status") == "Sandbox")
    prototype = sum(1 for x in use_cases if x.get("status") == "Prototype")
    in_progress = sum(1 for x in use_cases if x.get("status") == "In Progress")
    reusable_count = sum(1 for x in use_cases if as_number(x.get("reuse_score", 0)) >= 4)
    reusable_percent = round(safe_div(reusable_count, len(use_cases)) * 100, 1)
    roi = round(safe_div(total_value - implementation_cost, implementation_cost) * 100, 1) if implementation_cost else 0
    return {
        "active_use_cases": len(use_cases),
        "production": production,
        "sandbox": sandbox,
        "prototype": prototype,
        "in_progress": in_progress,
        "annual_value": total_value,
        "implementation_cost": implementation_cost,
        "hours_saved": total_hours,
        "avg_mttr": round(sum(as_number(x.get("mttr_improvement", 0)) for x in use_cases) / max(len(use_cases), 1), 1),
        "avg_reuse": round(sum(as_number(x.get("reuse_score", 0)) for x in use_cases) / max(len(use_cases), 1), 1),
        "reusable_count": reusable_count,
        "reusable_percent": reusable_percent,
        "portfolio_roi": roi,
        "tmf_current": as_number(settings.get("tmf_current", 1.8)),
        "tmf_target": as_number(settings.get("tmf_target", 3.0)),
    }

def active_targets(settings):
    active_year = settings.get("active_year", "FY27")
    targets = settings.get("targets", {}).get(active_year, {})
    return active_year, targets

def pct(current, target):
    return round(min(safe_div(current, target) * 100, 100), 1)


