def _first_present(row, *names, default=""):
    for name in names:
        if name in row and row.get(name) not in [None, ""]:
            return row.get(name)
        # case-insensitive fallback
        for k, v in row.items():
            if str(k).strip().lower() == str(name).strip().lower() and v not in [None, ""]:
                return v
    return default

def normalize_benefit_row(r):
    row = dict(BI_DEFAULTS)
    row.update({k: v for k, v in (r or {}).items() if k in BI_FIELDNAMES})
    row["benefit"] = str(_first_present(r, "benefit", "Benefit", default=row.get("benefit", ""))).strip()
    row["period"] = str(_first_present(r, "period", "Period", default=row.get("period", ""))).strip()
    row["actual"] = as_number(_first_present(r, "actual", "Actual", "value", "Value", default=row.get("actual", 0)))
    row["target"] = as_number(_first_present(r, "target", "Target", default=row.get("target", 0)))
    row["unit"] = str(_first_present(r, "unit", "Unit", default=row.get("unit", ""))).strip()
    row["owner"] = str(_first_present(r, "owner", "Owner", "benefit_owner", "Benefit Owner", default=row.get("owner", ""))).strip()
    row["commentary"] = str(_first_present(r, "commentary", "Commentary", "analysis", "Analysis", default=row.get("commentary", ""))).strip()
    # Numeric enrichment fields
    for k in ["previous_period", "variance_pct", "ytd_value", "fy_target", "confidence"]:
        row[k] = as_number(row.get(k, 0))
    # Fill useful identifiers if absent
    if not row.get("benefit_id"):
        base = ''.join(ch for ch in (row.get("benefit") or "BI")[:18].upper() if ch.isalnum()) or "BI"
        row["benefit_id"] = f"BI-{base}"
    if not row.get("benefit_category"):
        row["benefit_category"] = row.get("benefit", "")
    if not row.get("last_updated"):
        row["last_updated"] = datetime.datetime.now().strftime("%Y-%m-%d")
    return row

def save_benefit_history(rows):
    clean = []
    for r in rows:
        nr = normalize_benefit_row(r)
        if not nr.get("benefit") or not nr.get("period"):
            continue
        clean.append(nr)
    clean.sort(key=lambda x: (x.get("business_unit", ""), x.get("domain", ""), x.get("benefit", ""), benefit_period_key(x.get("period", ""))))
    save_json(BENEFITS_INTELLIGENCE_FILE, clean)

def benefit_period_key(period):
    txt = str(period or "").strip()
    for fmt in ["%Y-%m", "%Y/%m", "%b %Y", "%B %Y", "%Y-Q%q"]:
        try:
            if "%q" in fmt:
                break
            return datetime.datetime.strptime(txt, fmt).strftime("%Y-%m")
        except Exception:
            pass
    if len(txt) == 7 and txt[4] in ["-", "/"]:
        return txt.replace("/", "-")
    if "Q" in txt and len(txt) >= 6:
        return txt
    return txt

def _format_benefit_value(value, unit):
    try:
        value = float(value)
    except Exception:
        value = 0
    unit = unit or ""
    unit_txt = str(unit).strip()
    if unit_txt.upper() in ["R", "ZAR", "RAND", "RANDS"]:
        if abs(value) >= 1000000:
            return f"R{value/1000000:,.1f}m"
        return f"R{value:,.0f}"
    if unit_txt == "%":
        return f"{value:,.1f}%"
    if unit_txt.lower() in ["hrs", "hours", "hour"]:
        return f"{value:,.0f} hrs"
    return f"{value:,.1f} {unit_txt}".strip()

def _is_money_benefit(row_or_benefit):
    unit = str(row_or_benefit.get("unit", "") or "").strip().upper()
    name = str(row_or_benefit.get("benefit", row_or_benefit.get("name", "")) or "").strip().lower()
    category = str(row_or_benefit.get("benefit_category", "") or "").strip().lower()
    return unit in ["R", "ZAR", "RAND", "RANDS"] or category == "financial" or any(x in name for x in ["annual benefit", "cost", "revenue", "financial", "avoidance", "value"])

def _is_hours_benefit(row_or_benefit):
    unit = str(row_or_benefit.get("unit", "") or "").strip().lower()
    name = str(row_or_benefit.get("benefit", row_or_benefit.get("name", "")) or "").strip().lower()
    return unit in ["hrs", "hours", "hour"] or any(x in name for x in ["hour", "productivity", "capacity returned"])

def _is_mttr_benefit(row_or_benefit):
    name = str(row_or_benefit.get("benefit", row_or_benefit.get("name", "")) or "").strip().lower()
    return "mttr" in name

def _simple_forecast(values, periods=3):
    vals = [as_number(v, 0) for v in values]
    if not vals:
        return []
    if len(vals) == 1:
        step = 0
    else:
        recent = vals[-4:]
        diffs = [recent[i] - recent[i-1] for i in range(1, len(recent))]
        step = sum(diffs) / len(diffs) if diffs else 0
    out = []
    last = vals[-1]
    for _ in range(periods):
        last = max(0, last + step)
        out.append(round(last, 2))
    return out


