def _password_hash(password: str, salt: str | None = None) -> str:
    salt = salt or secrets.token_hex(16)
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), 120000).hex()
    return f"pbkdf2_sha256${salt}${digest}"

def _verify_password(password: str, stored_hash: str) -> bool:
    try:
        algo, salt, digest = stored_hash.split("$", 2)
        candidate = _password_hash(password, salt).split("$", 2)[2]
        return algo == "pbkdf2_sha256" and hmac.compare_digest(candidate, digest)
    except Exception:
        return False

def load_users():
    users = load_json(USERS_FILE, [])
    if not users:
        users = [{
            "username": "admin",
            "display_name": "System Administrator",
            "email": "admin@local",
            "role": "super_admin",
            "password_hash": _password_hash("ChangeMe123!"),
            "active": True,
            "domains": [],
            "mfa_enabled": False,
            "mfa_secret": "",
            "mfa_confirmed_at": ""
        }]
        save_json(USERS_FILE, users)
    return users

def save_users(users):
    save_json(USERS_FILE, users)

def ensure_super_admin_exists():
    """Prevent lock-out: if no super admin exists, promote the built-in admin user."""
    users = load_json(USERS_FILE, [])
    if not users:
        load_users()
        return
    if any(u.get("role") == "super_admin" and u.get("active", True) for u in users):
        return
    target = next((u for u in users if u.get("username") == "admin"), users[0])
    target["role"] = "super_admin"
    target["active"] = True
    save_json(USERS_FILE, users)

def get_current_user(request: Request):
    ensure_super_admin_exists()
    username = request.session.get("username")
    if not username:
        return None
    user = next((u for u in load_users() if u.get("username") == username and u.get("active", True)), None)
    return user

def require_login(request: Request):
    user = get_current_user(request)
    if not user:
        raise HTTPException(status_code=307, headers={"Location": "/login"})
    if MFA_REQUIRED and not request.session.get("mfa_passed"):
        request.session.clear()
        raise HTTPException(status_code=307, headers={"Location": "/login?error=MFA verification required"})
    return user

def require_admin(request: Request):
    user = require_login(request)
    if role_of(user) not in ["admin", "super_admin"]:
        raise HTTPException(status_code=403, detail="Admin access required")
    return user

def require_super_admin(request: Request):
    user = require_login(request)
    if role_of(user) != "super_admin":
        raise HTTPException(status_code=403, detail="Super admin access required")
    return user

def user_can_modify(user, item):
    if role_of(user) == "super_admin":
        return True
    if role_of(user) != "admin":
        return False

    username = (user.get("username") or "").strip().lower()
    email = (user.get("email") or "").strip().lower()
    display = (user.get("display_name") or "").strip().lower()
    owner_values = [
        str(item.get("created_by", "")).strip().lower(),
        str(item.get("owner_username", "")).strip().lower(),
        str(item.get("technical_owner", "")).strip().lower(),
        str(item.get("technical_owner_email", "")).strip().lower(),
    ]
    is_creator_or_owner = any(v and v in [username, email, display] for v in owner_values)

    item_domain = item.get("domain", "")
    allowed_domains = user_allowed_domains(user)
    has_domain_access = any(domains_match(item_domain, d) for d in allowed_domains)

    return is_creator_or_owner or has_domain_access

def user_can_create_in_domain(user, domain):
    if role_of(user) == "super_admin":
        return True
    if role_of(user) != "admin":
        return False
    allowed_domains = user_allowed_domains(user)
    # Admin users may create only in domains explicitly assigned by the super admin.
    return any(domains_match(domain, d) for d in allowed_domains)

def visible_admin_cases(user, cases):
    if role_of(user) == "super_admin":
        return cases
    return [c for c in cases if user_can_modify(user, c)]

def redirect_with_error(path: str, message: str):
    return RedirectResponse(f"{path}?error={message}", status_code=303)

@app.get("/login", response_class=HTMLResponse)
async def login_page(request: Request, error: str = ""):
    return templates.TemplateResponse("login.html", {"request": request, "error": error})

@app.post("/login")
async def login(request: Request, username: str = Form(...), password: str = Form(...)):
    username_clean = username.strip().lower()
    locked, remaining = _is_locked(username_clean)
    if locked:
        return RedirectResponse(f"/login?error=Account temporarily locked. Try again in {max(1, remaining//60)} minutes", status_code=303)
    user = next((u for u in load_users() if u.get("username", "").lower() == username_clean and u.get("active", True)), None)
    if not user or not _verify_password(password, user.get("password_hash", "")):
        _record_failed_login(request, username_clean)
        return RedirectResponse("/login?error=Invalid username or password", status_code=303)
    _clear_failed_login(username_clean)
    request.session.clear()
    if MFA_REQUIRED:
        # Password is valid; now require TOTP setup/verification before creating a full session.
        request.session["pending_mfa_username"] = user["username"]
        request.session["password_passed_at"] = int(time.time())
        if not user.get("mfa_enabled") or not user.get("mfa_secret"):
            _audit_event(request, user.get("username"), "mfa_setup_required", "user", user.get("username"))
            return RedirectResponse("/mfa/setup", status_code=303)
        return RedirectResponse("/mfa/verify", status_code=303)
    complete_login_after_mfa(request, user)
    _audit_event(request, user.get("username"), "login_success", "user", user.get("username"))
    return RedirectResponse("/", status_code=303)

@app.get("/mfa/setup", response_class=HTMLResponse)
async def mfa_setup_page(request: Request, error: str = ""):
    user = pending_mfa_user(request)
    if not user:
        return RedirectResponse("/login?error=Please sign in first", status_code=303)
    users = load_users()
    existing = next((u for u in users if u.get("username") == user.get("username")), None)
    if not existing:
        return RedirectResponse("/login?error=User not found", status_code=303)
    if not existing.get("mfa_secret"):
        existing["mfa_secret"] = generate_totp_secret()
        existing["mfa_enabled"] = False
        existing["mfa_confirmed_at"] = ""
        save_users(users)
        user = existing
    qr_uri = mfa_otpauth_uri(existing)
    qr_code = qrcode_data_uri(qr_uri)
    return templates.TemplateResponse("mfa_setup.html", {"request": request, "user": existing, "error": error, "qr_code": qr_code, "manual_secret": existing.get("mfa_secret")})

@app.post("/mfa/setup")
async def mfa_setup_verify(request: Request, code: str = Form(...)):
    user = pending_mfa_user(request)
    if not user:
        return RedirectResponse("/login?error=Please sign in first", status_code=303)
    locked, remaining = _is_locked(user.get("username", ""))
    if locked:
        request.session.clear()
        return RedirectResponse(f"/login?error=Account temporarily locked. Try again in {max(1, remaining//60)} minutes", status_code=303)
    if not verify_totp(user.get("mfa_secret", ""), code):
        _record_failed_login(request, user.get("username", ""))
        _audit_event(request, user.get("username"), "mfa_setup_failed", "user", user.get("username"))
        return RedirectResponse("/mfa/setup?error=Invalid authenticator code", status_code=303)
    users = load_users()
    existing = next((u for u in users if u.get("username") == user.get("username")), None)
    if existing:
        existing["mfa_enabled"] = True
        existing["mfa_confirmed_at"] = _utc_now()
        save_users(users)
    complete_login_after_mfa(request, existing or user)
    _clear_failed_login(user.get("username", ""))
    _audit_event(request, user.get("username"), "mfa_setup_success", "user", user.get("username"))
    _audit_event(request, user.get("username"), "login_success", "user", user.get("username"), {"mfa": True})
    return RedirectResponse("/", status_code=303)

