@app.post("/admin/save-use-case")
async def save_use_case(request: Request, user=Depends(require_admin)):
    form = await request.form()
    cases = load_use_cases()
    item = {}
    for field in FIELDS:
        value = form.get(field, "")
        if field in ["annual_value","implementation_cost","hours_saved","mttr_improvement","reuse_score"]:
            item[field] = normalise_metric_value(field, value)
        else:
            item[field] = str(value).strip()
    if not item.get("id"):
        return RedirectResponse("/admin/use-cases", status_code=303)
    if not user_can_create_in_domain(user, item.get("domain")):
        return redirect_with_error("/admin/use-cases", "You can only create use cases in your assigned domain(s)")
    item["updated_by"] = user.get("username")
    item["updated_at"] = datetime.datetime.utcnow().isoformat(timespec="seconds") + "Z"
    found = False
    for i, c in enumerate(cases):
        if c.get("id") == item["id"]:
            if not user_can_modify(user, c):
                return redirect_with_error("/admin/use-cases", "You can only modify use cases you created, own, or that are in your assigned domain(s)")
            # Preserve original creator metadata on edit. Do not change ownership/audit identity
            # just because another authorised user changed status or other fields.
            item["created_by"] = c.get("created_by", "")
            item["created_at"] = c.get("created_at", "")
            # Preserve the existing technical owner if the submitted form accidentally sends it blank.
            if not str(item.get("technical_owner", "")).strip():
                item["technical_owner"] = c.get("technical_owner", "")
            cases[i] = item
            found = True
            break
    if not found:
        item["created_by"] = user.get("username")
        item["created_at"] = item["updated_at"]
        cases.append(item)
    save_use_cases(cases)
    _audit_event(request, user.get("username"), "use_case_saved", "use_case", item.get("id"), {"domain": item.get("domain"), "new": not found})
    return RedirectResponse("/admin/use-cases", status_code=303)

