@app.post("/import/csv")
async def import_csv(request: Request, file: UploadFile = File(...), user=Depends(require_super_admin)):
    content = (await file.read()).decode("utf-8-sig")
    reader = csv.DictReader(io.StringIO(content))
    existing_cases = load_use_cases()
    existing_by_id = {str(item.get("id", "")).strip(): item for item in existing_cases if str(item.get("id", "")).strip()}
    imported_by_id = {}
    FIELD_ALIASES = {
        "technical_owner": ["technical_owner", "manager", "owner"],
        "sponsor": ["sponsor", "ehod", "executive_sponsor"],
    }

    def row_value(row, field):
        for candidate in FIELD_ALIASES.get(field, [field]):
            if candidate in row and row.get(candidate) not in [None, ""]:
                return row.get(candidate, "")
        return row.get(field, "")

    for row in reader:
        item = {k: row_value(row, k) for k in FIELDS}
        item_id = str(item.get("id", "")).strip()
        if not item_id:
            continue
        item["id"] = item_id

        # Evaluate numeric fields in dependency order so formulas like
        # annual_value = 700 * [[#This Row],[hours_saved]] import correctly.
        for n in ["hours_saved", "annual_value", "implementation_cost", "mttr_improvement", "reuse_score"]:
            raw_value = item.get(n, 0)
            if isinstance(raw_value, str) and raw_value.strip().startswith("="):
                item[n] = _eval_import_formula(raw_value, item, 0)
            else:
                item[n] = as_number(raw_value, 0)
        imported_by_id[item_id] = item
    existing_by_id.update(imported_by_id)
    existing_order = [str(item.get("id", "")).strip() for item in existing_cases if str(item.get("id", "")).strip()]
    new_ids = [item_id for item_id in imported_by_id.keys() if item_id not in existing_order]
    final_ids = existing_order + new_ids
    merged_cases = [existing_by_id[item_id] for item_id in final_ids if item_id in existing_by_id]
    save_use_cases(merged_cases)
    _audit_event(request, user.get("username"), "csv_imported", "use_case", "bulk", {"imported": len(imported_by_id), "total": len(merged_cases)})
    return RedirectResponse("/admin/use-cases", status_code=303)

