@app.post("/admin/benefits-intelligence/import")
async def import_benefit_history(request: Request, file: UploadFile = File(...), user=Depends(require_admin)):
    raw = await file.read()
    text = raw.decode("utf-8-sig")
    reader = csv.DictReader(io.StringIO(text))
    existing = [normalize_benefit_row(r) for r in load_benefit_history()]
    by_key = {(r.get("benefit", "").strip().lower(), r.get("period", "").strip().lower(), r.get("ai_use_case_id", "").strip().lower()): r for r in existing}
    count = 0
    for row in reader:
        nr = _sync_bi_row_to_use_case(normalize_benefit_row(row))
        if not nr.get("benefit") or not nr.get("period"):
            continue
        by_key[(nr.get("benefit", "").lower(), nr.get("period", "").lower(), nr.get("ai_use_case_id", "").lower())] = nr
        count += 1
    save_benefit_history(list(by_key.values()))
    _audit_event(request, user.get("username"), "benefit_history_import", "benefit", "csv", {"rows": count})
    return RedirectResponse("/admin/benefits-intelligence", status_code=303)

@app.get("/admin/benefits-intelligence/export")
async def export_benefit_history(user=Depends(require_admin)):
    output = io.StringIO()
    writer = csv.DictWriter(output, fieldnames=BI_FIELDNAMES, extrasaction="ignore")
    writer.writeheader()
    for row in load_benefit_history():
        writer.writerow({k: normalize_benefit_row(row).get(k, "") for k in BI_FIELDNAMES})
    return StreamingResponse(iter([output.getvalue()]), media_type="text/csv", headers={"Content-Disposition": "attachment; filename=benefits_intelligence_management_suite.csv"})

