@app.post("/profile/save")
async def save_profile(
    request: Request,
    display_name: str = Form(""),
    email: str = Form(""),
    current_password: str = Form(""),
    new_password: str = Form(""),
    confirm_password: str = Form(""),
    user=Depends(require_login)
):
    users = load_users()
    existing = next((u for u in users if u.get("username") == user.get("username")), None)
    if not existing:
        return redirect_with_error("/profile", "User profile not found")
    existing["display_name"] = display_name.strip() or existing.get("username")
    existing["email"] = email.strip()
    if new_password.strip():
        if not _verify_password(current_password, existing.get("password_hash", "")):
            return redirect_with_error("/profile", "Current password is incorrect")
        if new_password != confirm_password:
            return redirect_with_error("/profile", "New password and confirm password do not match")
        password_error = validate_password_strength(new_password)
        if password_error:
            return redirect_with_error("/profile", password_error)
        existing["password_hash"] = _password_hash(new_password)
    save_users(users)
    _audit_event(request, user.get("username"), "profile_saved", "user", user.get("username"), {"password_changed": bool(new_password.strip())})
    return RedirectResponse("/profile?success=Profile%20updated", status_code=303)

